+                } else if !ime.text.is_empty() {
+                    self.delete_selection();
+                    self.insert_text(&ime.text);
+                    true
+                } else {
+                    false
+                }
+            }
+            ImePhase::Cancel => self.ime_cancel_composition(),
+        }
